using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public required string Text { get; set; }

    /// <summary>
    /// Maximum number of sentences to include in the summary (default: 3).
    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalSentenceCount { get; set; }
    public int SummarySentenceCount { get; set; }
}

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    /// <summary>
    /// Produces an extractive summary by selecting the most important sentences.
    /// </summary>
    (string Summary, int OriginalCount, int SummaryCount) Summarize(string text, int maxSentences);
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class DocumentSummarizer : IDocumentSummarizer
{
    private static readonly HashSet<string> StopWords =
    [
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "for", "of", "with", "by", "from", "as",
        "into", "through", "during", "before", "after", "it", "its",
        "this", "that", "these", "those", "be", "been", "being", "have",
        "has", "had", "do", "does", "did", "will", "would", "shall",
        "should", "may", "might", "can", "could", "not", "no", "nor",
        "so", "if", "then", "than", "too", "very", "just", "about",
        "up", "out", "also", "he", "she", "they", "we", "you", "i"
    ];

    public (string Summary, int OriginalCount, int SummaryCount) Summarize(string text, int maxSentences)
    {
        var sentences = SplitSentences(text);

        if (sentences.Count <= maxSentences)
        {
            return (text.Trim(), sentences.Count, sentences.Count);
        }

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var scored = ScoreSentences(sentences, wordFrequencies);

        // Pick top-scored sentences, preserving original order
        var topIndices = scored
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .Select(s => s.Index)
            .OrderBy(i => i)
            .ToList();

        var summary = string.Join(" ", topIndices.Select(i => sentences[i].Trim()));
        return (summary, sentences.Count, topIndices.Count);
    }

    private static List<string> SplitSentences(string text)
    {
        return SentenceBoundary()
            .Split(text)
            .Where(s => !string.IsNullOrWhiteSpace(s))
            .ToList();
    }

    private static Dictionary<string, double> ComputeWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, double>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in ExtractWords(sentence))
            {
                if (!StopWords.Contains(word))
                {
                    freq[word] = freq.GetValueOrDefault(word) + 1;
                }
            }
        }

        if (freq.Count == 0) return freq;

        // Normalize by the maximum frequency
        var max = freq.Values.Max();
        foreach (var key in freq.Keys)
        {
            freq[key] /= max;
        }

        return freq;
    }

    private static List<(int Index, double Score)> ScoreSentences(
        List<string> sentences, Dictionary<string, double> wordFrequencies)
    {
        var scores = new List<(int Index, double Score)>();
        for (int i = 0; i < sentences.Count; i++)
        {
            double score = 0;
            var words = ExtractWords(sentences[i]);
            foreach (var word in words)
            {
                score += wordFrequencies.GetValueOrDefault(word);
            }

            // Normalize by word count to avoid bias toward long sentences
            if (words.Count > 0) score /= words.Count;

            scores.Add((i, score));
        }
        return scores;
    }

    private static List<string> ExtractWords(string text)
    {
        return WordPattern()
            .Matches(text)
            .Select(m => m.Value.ToLowerInvariant())
            .ToList();
    }

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceBoundary();

    [GeneratedRegex(@"\b[a-zA-Z]+\b", RegexOptions.Compiled)]
    private static partial Regex WordPattern();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController(IDocumentSummarizer summarizer) : ControllerBase
{
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var (summary, originalCount, summaryCount) = summarizer.Summarize(request.Text, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalSentenceCount = originalCount,
            SummarySentenceCount = summaryCount
        });
    }
}

